3_real_world_example.code:
const mathUtils = {
  add: (a, b) => a + b,
  subtract: (a, b) => a - b
};

// Create a new calculator object that inherits from mathUtils
const myCalc = Object.create(mathUtils);
myCalc.name = 'Casio';

// myCalc itself only has 'name'
console.log(Object.keys(myCalc)); // ['name']

// But it can seamlessly use mathUtils methods!
console.log(myCalc.add(5, 3)); // 8

